#include <stdio.h>
#include <string.h>
#include <math.h>

int main() {
    char number[100];
    scanf("%s", number);

    int length = strlen(number);
    int result = ceil(length / 2.0);

    int todas = 1;
    for (int index = 0; index < length; index++) {
        if (index == 0) {
            continue;
        } else {
            todas = todas && (number[index] == '0');
        }
    }

    if (todas && (length - 1) % 2 == 0) {
        result -= 1;
    }

    printf("%d\n", result);
    return 0;
}
